import urllib.request
import json
from functools import wraps
import time

def timeout(timeout_duration):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            start_time = time.time()
            result = None
            try:
                result = func(*args, **kwargs)
            except urllib.error.URLError as e:
                print(f"HTTPエラー: {e}")
            except Exception as e:
                print(f"その他のエラー: {e}")
            finally:
                if result is None and (time.time() - start_time) > timeout_duration:
                    raise TimeoutError("タイムアウトしました")
            return result
        return wrapper
    return decorator

@timeout(5)  # ここでタイムアウトの時間を設定
def fetch_json(url):
    data = urllib.request.urlopen(url).read()
    return json.loads(data)
```

